    nl: { title: "Bestellen & Levering: Veelgestelde Vragen", metaTitle: "Bestellen & Levering FAQ | ORYN Peptides", metaDescription: "ORYN bestel- en leverings-FAQ. Levertijden, betaalmethoden, gratis verzending en ordertracering.", introduction: "ORYN is toegewijd aan snelle, betrouwbare levering van onderzoekspeptiden in het VK en Europa, met veilige betaling via Stripe.", faqs: [{ question: "Hoe bestel ik?", answer: "Op orynpeptides.com. Bekijk producten, voeg toe aan winkelwagen en betaal via Stripe met creditcard." }, { question: "Betaalmethoden?", answer: "Visa, Mastercard, American Express via Stripe. Alle transacties versleuteld en PCI-conform." }, { question: "Gratis verzending?", answer: "Ja, voor bestellingen boven €150." }, { question: "Levertijden?", answer: "VK: doorgaans volgende dag. Europa: 2-5 werkdagen." }, { question: "Hoe worden pennen verzonden?", answer: "Temperatuurgecontroleerde verpakking om 2-8°C te handhaven tijdens transport." }, { question: "Ordertracering?", answer: "Ja, trackingnummer per email na verzending." }, { question: "Internationale verzending?", answer: "VK en voornaamste EU-landen." }, { question: "Beschadigde bestelling?", answer: "Contact opnemen met info@orynpeptides.com met foto's. Vervanging of terugbetaling geregeld." }, { question: "Kortingscode?", answer: "Ja, invoeren bij het afrekenen." }, { question: "Groothandelsprijzen?", answer: "Ja, contact opnemen met wholesale@orynpeptides.com." }] },
    pl: { title: "Zamówienia i Dostawa: Często Zadawane Pytania", metaTitle: "FAQ Zamówienia i Dostawa | ORYN Peptides", metaDescription: "FAQ zamówień ORYN. Czasy dostawy, metody płatności, bezpłatna wysyłka i śledzenie zamówień.", introduction: "ORYN jest zaangażowana w szybką, niezawodną dostawę peptydów badawczych w Wielkiej Brytanii i Europie, z bezpieczną płatnością przez Stripe.", faqs: [{ question: "Jak złożyć zamówienie?", answer: "Na orynpeptides.com. Przeglądaj produkty, dodaj do koszyka i zapłać przez Stripe kartą kredytową." }, { question: "Metody płatności?", answer: "Visa, Mastercard, American Express przez Stripe. Wszystkie transakcje szyfrowane i zgodne z PCI." }, { question: "Bezpłatna wysyłka?", answer: "Tak, dla zamówień powyżej €150." }, { question: "Czasy dostawy?", answer: "Wielka Brytania: zazwyczaj następnego dnia. Europa: 2-5 dni roboczych." }, { question: "Jak są wysyłane pisaki?", answer: "Opakowanie z kontrolą temperatury utrzymujące 2-8°C podczas transportu." }, { question: "Śledzenie zamówienia?", answer: "Tak, numer śledzenia emailem po wysyłce." }, { question: "Wysyłka międzynarodowa?", answer: "Wielka Brytania i główne kraje UE." }, { question: "Uszkodzone zamówienie?", answer: "Skontaktuj się z info@orynpeptides.com ze zdjęciami. Wymiana lub zwrot zostanie zorganizowany." }, { question: "Kod promocyjny?", answer: "Tak, wpisz w pole kodu promocyjnego przy kasie." }, { question: "Ceny hurtowe?", answer: "Tak, skontaktuj się z wholesale@orynpeptides.com." }] },
