// ─── Public API ───────────────────────────────────────────────────────────────

export function getLocalizedFAQHub(
  slug: string,
  locale: Locale
): FAQHubTranslation | undefined {
  return faqHubTranslations[slug]?.[locale] ?? faqHubTranslations[slug]?.["en"];
}

export function hasTranslation(slug: string, locale: Locale): boolean {
  return slug in faqHubTranslations && locale in (faqHubTranslations[slug] ?? {});
}

export { faqHubTranslations };
